package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnPostApproveProxy struct {
	automation.UnimplementedOnPostApproveServer
	client automation.OnPostApproveClient
}

func init() {
	proxyutil.Register(&automation.OnPostApprove_ServiceDesc, NewOnPostApproveProxy)
}
func NewOnPostApproveProxy(cc grpc.ClientConnInterface) automation.OnPostApproveServer {
	return &OnPostApproveProxy{client: automation.NewOnPostApproveClient(cc)}
}
func (p *OnPostApproveProxy) OnPostApprove(ctx context.Context, in *events.PostApprove) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.PostApprove, automation.HandlerResult](p.client.OnPostApprove)(ctx, in)
}
